  /**
   * Generate a pre-commit hook script that validates lock file consistency
   */
  generatePreCommitHook() {
    const hookScript = `#!/bin/sh
# Pre-commit hook: Validate package-lock.json consistency
# Install: cp this file to .git/hooks/pre-commit && chmod +x .git/hooks/pre-commit
# Or use husky: npx husky add .husky/pre-commit "node package-lock-manager.js hook:pre-commit"

echo "🔍 Validating package-lock.json..."

# Check if package.json was modified
PACKAGE_JSON_STAGED=$(git diff --cached --name-only -- package.json)

if [ -n "$PACKAGE_JSON_STAGED" ]; then
  # package.json was modified, ensure package-lock.json is also staged
  LOCK_STAGED=$(git diff --cached --name-only -- package-lock.json)
  
  if [ -z "$LOCK_STAGED" ]; then
    echo "❌ ERROR: package.json was modified but package-lock.json was not."
    echo "   Run 'npm install' and stage the updated package-lock.json."
    exit 1
  fi
fi

# If package-lock.json is staged, validate it
LOCK_STAGED=$(git diff --cached --name-only -- package-lock.json)
if [ -n "$LOCK_STAGED" ]; then
  # Verify the lock file is valid JSON
  node -e "JSON.parse(require('fs').readFileSync('package-lock.json', 'utf-8'))" 2>/dev/null
  if [ $? -ne 0 ]; then
    echo "❌ ERROR: package-lock.json is not valid JSON."
    exit 1
  fi
  
  echo "✅ package-lock.json validation passed."
fi

exit 0
`;

    // Write as a standalone script
    const hookPath = path.join(this.projectRoot, 'scripts', 'pre-commit-lock-check.sh');
    const scriptsDir = path.dirname(hookPath);

    if (!fs.existsSync(scriptsDir)) {
      fs.mkdirSync(scriptsDir, { recursive: true });
    }

    fs.writeFileSync(hookPath, hookScript, { mode: 0o755 });
    console.log(`✅ Pre-commit hook script generated at: ${hookPath}`);
    console.log('\nTo install with husky:');
    console.log('  npm install --save-dev husky');
    console.log('  npx husky install');
    console.log(`  npx husky add .husky/pre-commit "sh ${hookPath}"\n`);

    return hookScript;
  }

