// =========================================================================
// CLI Entry Point
// =========================================================================

function main() {
  const manager = new PackageLockManager();
  const args = process.argv.slice(2);
  const command = args[0] || 'help';

  const commands = {
    'generate': () => manager.generateLockFile(),
    'generate-only': () => manager.generateLockFileOnly(),
    'ci': () => manager.cleanInstall(),
    'ci:production': () => manager.cleanInstall({ production: true }),
    'validate': () => manager.validateLockFile(),
    'audit': () => manager.auditDependencies(),
    'audit:fix': () => manager.auditDependencies({ fix: true }),
    'outdated': () => manager.checkOutdated(),
    'update': () => manager.updateDependencies(),
    'update:dry-run': () => manager.updateDependencies({ dryRun: true }),
    'update:package': () => {
      const pkg = args[1];
      const version = args[2] || 'latest';
      if (!pkg) {
        console.error('Usage: update:package <package-name> [version]');
        process.exit(1);
      }
      manager.updatePackage(pkg, version);
    },
    'backup': () => manager.backupLockFile(args[1] || ''),
    'restore': () => manager.restoreLockFile(args[1] || ''),
    'backups': () => manager.listBackups(),
    'hash': () => manager.getLockFileHash(),
    'compare': () => {
      if (args.length < 3) {
        console.error('Usage: compare <lock-file-1> <lock-file-2>');
        process.exit(1);
      }
      manager.compareLockFiles(args[1], args[2]);
    },
    'stats': () => manager.getStats(),
    'ci-config': () => manager.generateCIPipelineConfig(args[1] || 'github-actions'),
    'npmrc': () => manager.generateNpmrc(),
    'pre-commit': () => manager.generatePreCommitHook(),
    'docs': () => manager.generateDocumentation(),
    'hook:pre-commit': () => {
      // Called by git pre-commit hook
      const report = manager.validateLockFile();
      if (!report.valid) {
        process.exit(1);
      }
    },
    'help': () => {
      console.log(`
📦 Package Lock Manager - Consistent Dependency Management

Usage: node package-lock-manager.js <command> [options]

Commands:
  generate          Generate package-lock.json (runs npm install)
  generate-only     Generate lock file without installing (--package-lock-only)
  ci                Clean install from lock file (npm ci) - for CI/CD
  ci:production     Clean install, production deps only
  validate          Validate lock file is in sync with package.json
  audit             Check for known vulnerabilities
  audit:fix         Auto-fix vulnerabilities
  outdated          Check for outdated dependencies
  update            Update dependencies within semver ranges
  update:dry-run    Preview what would be updated
  update:package    Update a specific package: update:package <name> [version]
  backup [label]    Backup current lock file
  restore [label]   Restore lock file from backup
  backups           List available backups
  hash              Get SHA-256 hash of lock file
  compare <f1> <f2> Compare two lock files
  stats             Show lock file statistics
  ci-config [plat]  Generate CI config (github-actions|gitlab-ci|jenkins|dockerfile)
  npmrc             Generate .npmrc configuration
  pre-commit        Generate pre-commit hook script
  docs              Generate team documentation (Markdown)
  help              Show this help message

Examples:
  node package-lock-manager.js ci                    # Clean install for CI/CD
  node package-lock-manager.js validate              # Check lock file health
  node package-lock-manager.js ci-config dockerfile   # Get Dockerfile template
  node package-lock-manager.js update:package react 18.2.0
  node package-lock-manager.js compare old-lock.json new-lock.json
`);
    }
  };

  const handler = commands[command];
  if (!handler) {
    console.error(`Unknown command: ${command}`);
    console.log('Run with "help" for available commands.');
    process.exit(1);
  }

  try {
    handler();
  } catch (error) {
    console.error(`\n💥 Command "${command}" failed: ${error.message}`);
    process.exit(1);
  }
}

// Run CLI if executed directly
if (require.main === module) {
  main();
}

// Export for programmatic use
module.exports = PackageLockManager;